const body = $json.body ?? $json;
const configuredSecret = $vars.LS_N8N_CLIENT_SECRET;
if (!configuredSecret) throw new Error('LS_N8N_CLIENT_SECRET is not configured');
if (!body.clientSecret || body.clientSecret !== configuredSecret) throw new Error('Invalid client secret');
const opportunityID = body.opportunity?.opportunityID ?? body.opportunityID;
if (!opportunityID) throw new Error('opportunity.opportunityID is required');
if (!body.message || !String(body.message).trim()) throw new Error('message is required');
const configuredBaseUrl = $vars.ACUMATICA_BASE_URL || 'http://172.17.0.3/AcumaticaERP';
const acumaticaBaseUrl = String(configuredBaseUrl).replace(/\/$/, '');
const endpointBase = acumaticaBaseUrl + '/entity/LSOpportunityNotes/25.200.001';
const escapedOpportunityID = String(opportunityID).replace(/'/g, "''");
const notesFilter = "ConfirmedOpportunityID eq '" + escapedOpportunityID + "'";
return [{ json: {
  chatInput: 'User question: ' + String(body.message).trim() + '\n\nCurrent opportunity context supplied by Acumatica side panel:\n' + JSON.stringify(body.opportunity ?? { opportunityID }, null, 2) + '\n\nUse the connected tools to fetch current OpportunityChatContext and related OpportunityNotesApproval transcripts for opportunity ' + opportunityID + '. Answer conversationally for the Acumatica side-panel chat. Do not mutate Acumatica data.',
  chatSessionID: body.chatSessionID,
  opportunity: body.opportunity ?? { opportunityID },
  opportunityID,
  contextUrl: endpointBase + '/OpportunityChatContext/' + encodeURIComponent(opportunityID),
  notesUrl: endpointBase + '/OpportunityNotesApproval?$filter=' + encodeURIComponent(notesFilter),
}}];
